solution:
// Total sales amount per category
db.sales.aggregate([
  { $group: {
      _id: '$category',
      totalSales: { $sum: '$amount' },
      count: { $sum: 1 },
      avgSale: { $avg: '$amount' }
  }},
  { $sort: { totalSales: -1 } },
  { $limit: 5 }
]);

// Monthly sales trend
db.sales.aggregate([
  { $match: { date: { $gte: new Date('2024-01-01') } } },
  { $group: {
      _id: {
        year: { $year: '$date' },
        month: { $month: '$date' }
      },
      total: { $sum: '$amount' }
  }},
  { $sort: { '_id.year': 1, '_id.month': 1 } }
]);

// Top sellers with their categories (join with sellers collection)
db.sales.aggregate([
  { $lookup: {
      from: 'sellers',
      localField: 'seller',
      foreignField: '_id',
      as: 'sellerInfo'
  }},
  { $unwind: '$sellerInfo' },
  { $group: {
      _id: '$sellerInfo.name',
      totalRevenue: { $sum: '$amount' }
  }},
  { $sort: { totalRevenue: -1 } },
  { $limit: 10 }
]);

