  // Implement atomic transfer using session/transaction
}

solution:
const mongoose = require('mongoose');

async function transferMoney(fromId, toId, amount) {
  const session = await mongoose.startSession();

  try {
    session.startTransaction();

    const fromAccount = await Account.findById(fromId).session(session);
    const toAccount = await Account.findById(toId).session(session);

    if (!fromAccount || !toAccount) {
      throw new Error('Account not found');
    }

    if (fromAccount.balance < amount) {
      throw new Error('Insufficient funds');
    }

    // Debit
    await Account.findByIdAndUpdate(
      fromId,
      { $inc: { balance: -amount } },
      { session, new: true }
    );

    // Credit
    await Account.findByIdAndUpdate(
      toId,
      { $inc: { balance: amount } },
      { session, new: true }
    );

    // Record transaction
    await Transaction.create([{
      from: fromId, to: toId, amount,
      timestamp: new Date(), status: 'completed'
    }], { session });

    await session.commitTransaction();
    console.log('Transfer successful!');
  } catch (error) {
    await session.abortTransaction();
    console.error('Transfer failed, rolled back:', error.message);
    throw error;
  } finally {
    session.endSession();
  }
}

