  // Watch for order changes
}

solution:
const mongoose = require('mongoose');

async function watchOrders() {
  const pipeline = [
    { $match: {
        $or: [
          { operationType: 'insert' },
          { operationType: 'update' },
          { 'fullDocument.status': 'shipped' }
        ]
    }}
  ];

  const changeStream = Order.watch(pipeline, { fullDocument: 'updateLookup' });

  changeStream.on('change', (change) => {
    switch (change.operationType) {
      case 'insert':
        console.log('New order:', change.fullDocument);
        notifyUser(change.fullDocument.userId, 'Order placed!');
        break;
      case 'update':
        console.log('Order updated:', change.documentKey._id);
        if (change.fullDocument?.status === 'shipped') {
          sendShippingEmail(change.fullDocument);
        }
        break;
      case 'delete':
        console.log('Order deleted:', change.documentKey._id);
        break;
    }
  });

  changeStream.on('error', (error) => {
    console.error('Change stream error:', error);
    // Reconnect logic
    setTimeout(watchOrders, 1000);
  });

  // Close stream gracefully
  process.on('SIGTERM', () => changeStream.close());
}

watchOrders();
